import{_ as a,o,c as r,a0 as s}from"./chunks/framework.DZNqfkJl.js";const u=JSON.parse('{"title":"Herramientas Requeridas","description":"","frontmatter":{},"headers":[],"relativePath":"tools.md","filePath":"tools.md"}'),t={name:"tools.md"};function n(i,e,l,d,c,p){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="herramientas-requeridas" tabindex="-1">Herramientas Requeridas <a class="header-anchor" href="#herramientas-requeridas" aria-label="Permalink to &quot;Herramientas Requeridas&quot;">​</a></h1><p>Para desarrollar y ejecutar el proyecto <strong>Structo</strong>, es necesario instalar las siguientes herramientas en tu entorno de desarrollo.</p><p>El proyecto está compuesto por un backend en .NET y un frontend en Nuxt.js, e interactúa con bases de datos SQL Server y MongoDB.</p><h2 id="herramientas-base-requeridas" tabindex="-1">Herramientas Base (Requeridas) <a class="header-anchor" href="#herramientas-base-requeridas" aria-label="Permalink to &quot;Herramientas Base (Requeridas)&quot;">​</a></h2><h3 id="_1-node-js-22-npm" tabindex="-1">1. Node.js 22+ &amp; npm <a class="header-anchor" href="#_1-node-js-22-npm" aria-label="Permalink to &quot;1. Node.js 22+ &amp; npm&quot;">​</a></h3><p>Requerido para el frontend (Nuxt) y para la documentación (VitePress).</p><ul><li><strong>Propósito</strong>: Ejecutar el servidor de desarrollo de Nuxt, compilar el frontend, y gestionar las dependencias del ecosistema JavaScript.</li><li><strong>Instalación</strong>: Instala la versión <strong>22 o superior</strong>. Puedes descargarlo desde <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a> o usar un gestor de versiones como <code>nvm</code>.</li></ul><h3 id="_2-net-sdk-10" tabindex="-1">2. .NET SDK 10 <a class="header-anchor" href="#_2-net-sdk-10" aria-label="Permalink to &quot;2. .NET SDK 10&quot;">​</a></h3><p>Requerido para el backend escrito en C#. Asegúrate de instalar la versión <strong>10</strong>.</p><ul><li><strong>Propósito</strong>: Compilar y ejecutar la solución <code>Structo.sln</code> y los diversos proyectos ubicados en la carpeta donde se encuentra el backend.</li><li><strong>Instalación</strong>: Descarga e instala el .NET 10 SDK desde la <a href="https://dotnet.microsoft.com/download" target="_blank" rel="noreferrer">página oficial de Microsoft</a>.</li></ul><h4 id="entity-framework-core-tools-dotnet-ef" tabindex="-1">Entity Framework Core Tools (dotnet-ef) <a class="header-anchor" href="#entity-framework-core-tools-dotnet-ef" aria-label="Permalink to &quot;Entity Framework Core Tools (dotnet-ef)&quot;">​</a></h4><p>Adicionalmente, se requiere la herramienta global de EF Core para gestionar las migraciones de la base de datos.</p><ul><li><strong>Instalación</strong>: Ejecuta el siguiente comando en tu terminal luego de instalar el SDK de .NET:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dotnet-ef</span></span></code></pre></div></li></ul><h3 id="_3-sql-server" tabindex="-1">3. SQL Server <a class="header-anchor" href="#_3-sql-server" aria-label="Permalink to &quot;3. SQL Server&quot;">​</a></h3><p>Requerido como base de datos relacional del sistema.</p><ul><li><strong>Propósito</strong>: Almacenar la información principal de la plataforma.</li><li><strong>Instalación</strong>: Puedes instalar <a href="https://www.microsoft.com/es-es/sql-server/sql-server-downloads" target="_blank" rel="noreferrer">SQL Server Developer Edition</a> de forma local.</li></ul><h3 id="_4-mongodb" tabindex="-1">4. MongoDB <a class="header-anchor" href="#_4-mongodb" aria-label="Permalink to &quot;4. MongoDB&quot;">​</a></h3><p>Requerido como base de datos NoSQL del sistema.</p><ul><li><strong>Propósito</strong>: Almacenar documentos y datos no relacionales de la plataforma.</li><li><strong>Instalación</strong>: Descarga e instala <a href="https://www.mongodb.com/try/download/community" target="_blank" rel="noreferrer">MongoDB Community Server</a>.</li></ul><h3 id="_5-git" tabindex="-1">5. Git <a class="header-anchor" href="#_5-git" aria-label="Permalink to &quot;5. Git&quot;">​</a></h3><p>Requerido para el control de versiones.</p><ul><li><strong>Propósito</strong>: Clonar el repositorio y gestionar los cambios en el código.</li><li><strong>Instalación</strong>: Disponible en <a href="https://git-scm.com/" target="_blank" rel="noreferrer">git-scm.com</a>.</li></ul><hr><h2 id="herramientas-opcionales-recomendadas" tabindex="-1">Herramientas Opcionales / Recomendadas <a class="header-anchor" href="#herramientas-opcionales-recomendadas" aria-label="Permalink to &quot;Herramientas Opcionales / Recomendadas&quot;">​</a></h2><h3 id="docker-y-docker-compose-opcional" tabindex="-1">Docker y Docker Compose (Opcional) <a class="header-anchor" href="#docker-y-docker-compose-opcional" aria-label="Permalink to &quot;Docker y Docker Compose (Opcional)&quot;">​</a></h3><p>Si prefieres no instalar los servicios (como las bases de datos) directamente en tu equipo local, puedes levantarlos utilizando contenedores.</p><ul><li><strong>Propósito</strong>: Levantar las dependencias de infraestructura localmente de manera aislada.</li><li><strong>Instalación</strong>: Instala <a href="https://www.docker.com/products/docker-desktop/" target="_blank" rel="noreferrer">Docker Desktop</a> (Windows/Mac) o Docker Engine (Linux). Asegúrate de que <code>docker-compose</code> esté disponible.</li></ul><h3 id="dbeaver-recomendado" tabindex="-1">DBeaver (Recomendado) <a class="header-anchor" href="#dbeaver-recomendado" aria-label="Permalink to &quot;DBeaver (Recomendado)&quot;">​</a></h3><ul><li><strong>Propósito</strong>: Cliente visual universal para la gestión de bases de datos relacionales, muy útil para interactuar con SQL Server.</li><li><strong>Instalación</strong>: Disponible de forma gratuita en <a href="https://dbeaver.io/" target="_blank" rel="noreferrer">dbeaver.io</a>.</li></ul><p><em>(Alternativas: SQL Server Management Studio (SSMS) o Azure Data Studio).</em></p><h3 id="mongodb-compass-recomendado" tabindex="-1">MongoDB Compass (Recomendado) <a class="header-anchor" href="#mongodb-compass-recomendado" aria-label="Permalink to &quot;MongoDB Compass (Recomendado)&quot;">​</a></h3><ul><li><strong>Propósito</strong>: Interfaz gráfica oficial para explorar e interactuar con tus colecciones y bases de datos en MongoDB.</li><li><strong>Instalación</strong>: Puedes descargarlo desde <a href="https://www.mongodb.com/products/tools/compass" target="_blank" rel="noreferrer">mongodb.com/products/tools/compass</a>.</li></ul>',32)])])}const h=a(t,[["render",n]]);export{u as __pageData,h as default};
